const notificationHubCss = "\n.notification-head-actions{display:flex;align-items:center;gap:10px}.notification-head-actions a{color:#d4dce7;font-size:9.5px;text-decoration:none}.notification-head-actions a:hover{color:var(--accent)}\n.notification-item{color:inherit;text-decoration:none}.notification-copy{min-width:0}.notification-copy strong,.notification-copy span{overflow-wrap:anywhere}.notification-item-time{margin-top:4px!important;color:#657183!important;font-size:8.8px!important}.notification-item.unread .notification-copy strong:after{content:\"\";display:inline-block;width:5px;height:5px;margin-inline-start:6px;border-radius:50%;background:var(--accent);vertical-align:middle}\n.notification-hub{display:grid;gap:11px}.notification-hub-hero{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:18px;align-items:end;padding:18px}.notification-hub-hero h1{margin:0 0 6px;font-size:20px;font-weight:600}.notification-hub-hero p{max-width:580px;margin:0;color:var(--muted);font-size:11px;line-height:1.55}.notification-hub-count{display:grid;min-width:92px;text-align:end}.notification-hub-count strong{color:var(--accent);font-size:24px;font-weight:650}.notification-hub-count span{color:#7e8999;font-size:9px}\n.notification-toolbar{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:8px 10px;border:1px solid var(--line);border-radius:7px;background:#0d1118}.notification-filters{display:flex;gap:3px}.notification-filters button{min-height:30px;padding:0 12px;border:0;border-radius:5px;background:transparent;color:#8793a5;font-size:10px;font-weight:600}.notification-filters button.active{background:#182315;color:#c8ef75}.notification-mark-all{border:0;background:transparent;color:#a7d65a;font-size:9.8px;font-weight:600}\n.notification-hub-list{overflow:hidden;border:1px solid var(--line);border-radius:7px;background:#0d1017}.notification-hub-item{display:grid;grid-template-columns:42px minmax(0,1fr) auto;gap:11px;align-items:center;padding:13px 14px;border-top:1px solid var(--line2);color:inherit;text-decoration:none}.notification-hub-item:first-child{border-top:0}.notification-hub-item:hover{background:#121822}.notification-hub-item.unread{background:#101a13}.notification-hub-item.unread:hover{background:#142019}.notification-hub-avatar{width:42px;height:42px;display:grid;place-items:center;border:1px solid #334128;border-radius:50%;background:#141b25;color:var(--accent);font-size:11px;font-weight:700}.notification-hub-copy{min-width:0}.notification-hub-copy strong{display:block;color:#dce2da;font-size:11.5px;font-weight:600;line-height:1.45}.notification-hub-copy p{margin:3px 0 0;color:#8793a4;font-size:10px;line-height:1.45;overflow-wrap:anywhere}.notification-hub-meta{display:grid;justify-items:end;gap:6px;color:#6f7b8c;font-size:9px;white-space:nowrap}.notification-new{padding:3px 6px;border-radius:999px;background:#233516;color:#bfe878;font-size:8px;font-weight:650}.notification-hub-empty,.notification-hub-gate{padding:40px 18px;text-align:center}.notification-hub-empty strong,.notification-hub-gate h2{display:block;margin:0 0 6px;font-size:14px}.notification-hub-empty span,.notification-hub-gate p{color:#7f8b9c;font-size:10.5px;line-height:1.5}.notification-hub-gate a{display:inline-flex;align-items:center;min-height:34px;margin-top:13px;padding:0 14px;border-radius:6px;background:var(--accent);color:#10150b;font-size:10.5px;font-weight:650;text-decoration:none}.notification-load-more{justify-self:center;min-height:34px;padding:0 14px;border:1px solid #344127;border-radius:6px;background:#141d11;color:#bfe878;font-size:10px;font-weight:600}\n@media(max-width:700px){.notification-hub-hero{grid-template-columns:1fr}.notification-hub-count{text-align:start}.notification-toolbar{align-items:stretch;flex-direction:column}.notification-mark-all{align-self:flex-start;padding:7px 4px}.notification-hub-item{grid-template-columns:36px minmax(0,1fr)}.notification-hub-avatar{width:36px;height:36px}.notification-hub-meta{grid-column:2;justify-items:start;grid-auto-flow:column;justify-content:start}.notification-head-actions{gap:7px}}\n";

const notificationHubPage = (locale) => {
  const copy = notificationHubI18n[locale];
  return `<section class="notification-hub" data-notification-hub>
    <header class="panel notification-hub-hero"><div><h1>${copy.title}</h1><p>${copy.intro}</p></div><div class="notification-hub-count"><strong data-notification-unread>0</strong><span>${copy.unreadOnly}</span></div></header>
    <div class="notification-toolbar"><div class="notification-filters" data-notification-filters><button class="active" type="button" data-notification-filter="all">${copy.all}</button><button type="button" data-notification-filter="unread">${copy.unreadOnly}</button></div><button class="notification-mark-all" type="button" data-notification-mark-all>${copy.markAll}</button></div>
    <div class="notification-hub-list" data-notification-hub-list><div class="notification-hub-empty"><span>${copy.loading}</span></div></div>
    <button class="notification-load-more hidden" type="button" data-notification-load-more>${copy.loadMore}</button>
  </section>`;
};

const notificationHubClientJs = "(function(){\n  \"use strict\";\n  var config=window.__FN_CONFIG__||{},page=window.__FN_PAGE__||{},copy=page.notificationHub||{},storageKey=\"football_network_session\",filter=\"all\",offset=0,pageSize=20,hubItems=[];\n  function q(selector,root){return (root||document).querySelector(selector)}\n  function qa(selector,root){return Array.prototype.slice.call((root||document).querySelectorAll(selector))}\n  function esc(value){return String(value==null?\"\":value).replace(/[&<>\"']/g,function(char){return({\"&\":\"&amp;\",\"<\":\"&lt;\",\">\":\"&gt;\",'\"':\"&quot;\",\"'\":\"&#39;\"})[char]})}\n  function session(){try{return JSON.parse(localStorage.getItem(storageKey)||\"null\")}catch(error){return null}}\n  async function api(path,body){var current=session();if(!current||!current.access_token)throw new Error(\"authentication_required\");var response=await fetch(String(config.supabaseUrl||\"\").replace(/\\/$/,\"\")+path,{method:\"POST\",headers:{apikey:config.anonKey,Authorization:\"Bearer \"+current.access_token,\"content-type\":\"application/json\"},body:JSON.stringify(body||{})}),text=await response.text(),data=null;try{data=text?JSON.parse(text):null}catch(error){}if(!response.ok)throw new Error(data&&(data.message||data.error_description)||text||\"request_failed\");return data}\n  function initials(item){var name=item.actor&&item.actor.display_name||copy.platform||\"FN\",parts=String(name).trim().split(/\\s+/);return ((parts[0]||\"F\")[0]+(parts.length>1?(parts[parts.length-1]||\"\")[0]:\"\")).toUpperCase()}\n  function when(value){var date=new Date(value),seconds=Math.round((date.getTime()-Date.now())/1000),abs=Math.abs(seconds),unit=\"second\",amount=seconds;if(abs>=86400){unit=\"day\";amount=Math.round(seconds/86400)}else if(abs>=3600){unit=\"hour\";amount=Math.round(seconds/3600)}else if(abs>=60){unit=\"minute\";amount=Math.round(seconds/60)}try{return new Intl.RelativeTimeFormat(page.locale||\"fr\",{numeric:\"auto\"}).format(amount,unit)}catch(error){return date.toLocaleDateString(page.locale||\"fr\")}}\n  function status(value){return copy.statuses&&copy.statuses[value]||value||\"\"}\n  function presentation(item){var type=item.notification_type,payload=item.payload||{},actor=item.actor&&item.actor.display_name||copy.platform||\"Football Network\",title=copy.platform,detail=payload.title||payload.preview||\"\",route=\"/\"+page.locale;\n    if(type===\"post_reaction\"){title=actor+\" \"+copy.postReaction;route+=\"/?post=\"+encodeURIComponent(payload.post_id||item.entity_id)}\n    else if(type===\"post_comment\"){title=actor+\" \"+copy.postComment;route+=\"/?post=\"+encodeURIComponent(payload.post_id||item.entity_id)}\n    else if(type===\"opportunity_match\"){title=copy.opportunityMatch;route+=\"/opportunities\"}\n    else if(type===\"application_received\"){title=actor+\" \"+copy.applicationReceived;route+=\"/opportunities\"}\n    else if(type===\"application_status\"){title=copy.applicationStatus;detail=[payload.title,status(payload.status)].filter(Boolean).join(\" · \");route+=\"/opportunities\"}\n    else if(type===\"verification_submitted\"){title=actor+\" \"+copy.verificationSubmitted;detail=payload.verification_type||\"\";route+=\"/admin\"}\n    else if(type===\"verification_status\"){title=copy.verificationStatus;detail=copy.status+\": \"+status(payload.status);route+=\"/account#verification\"}\n    else if(type===\"club_claim_submitted\"){title=actor+\" \"+copy.clubClaimSubmitted;detail=payload.organization_role||\"\";route+=\"/admin\"}\n    else if(type===\"club_claim_status\"){title=copy.clubClaimStatus;detail=copy.status+\": \"+status(payload.status);route+=\"/organizations?claims=mine\"}\n    else if(type===\"connection_request\"){title=actor+\" \"+copy.connectionRequest;route+=\"/network\"}\n    else if(type===\"connection_status\"){title=actor+\" \"+(payload.status===\"accepted\"?copy.connectionAccepted:copy.connectionRejected);route+=\"/network\"}\n    else if(type===\"direct_message\"){title=actor+\" \"+copy.directMessage;detail=payload.preview||\"\";route+=\"/messages\"+(payload.conversation_id?\"?conversation=\"+encodeURIComponent(payload.conversation_id):\"\")}\n    return {title:title,detail:detail,route:route}\n  }\n  function card(item,large){var view=presentation(item),unread=!item.read,time=when(item.created_at);if(large)return '<a class=\"notification-hub-item'+(unread?' unread':'')+'\" href=\"'+esc(view.route)+'\" data-notification-link data-notification-id=\"'+esc(item.id)+'\"><span class=\"notification-hub-avatar\">'+esc(initials(item))+'</span><span class=\"notification-hub-copy\"><strong>'+esc(view.title)+'</strong>'+(view.detail?'<p>'+esc(view.detail)+'</p>':'')+'</span><span class=\"notification-hub-meta\"><time>'+esc(time)+'</time>'+(unread?'<span class=\"notification-new\">'+esc(copy.newLabel)+'</span>':'')+'</span></a>';return '<a class=\"notification-item'+(unread?' unread':'')+'\" href=\"'+esc(view.route)+'\" data-notification-link data-notification-id=\"'+esc(item.id)+'\"><span class=\"notification-avatar\">'+esc(initials(item))+'</span><span class=\"notification-copy\"><strong>'+esc(view.title)+'</strong>'+(view.detail?'<span>'+esc(view.detail)+'</span>':'')+'<span class=\"notification-item-time\">'+esc(time)+'</span></span></a>'}\n  function gate(root,profileRequired){var title=profileRequired?copy.profileRequired:copy.signInTitle,text=profileRequired?\"\":copy.signInText,label=profileRequired?copy.createProfile:copy.signIn;root.innerHTML='<div class=\"notification-hub-gate\"><h2>'+esc(title)+'</h2>'+(text?'<p>'+esc(text)+'</p>':'')+'<a href=\"/'+page.locale+'/account\">'+esc(label)+'</a></div>'}\n  async function fetchInbox(selected,limit,start){return api(\"/rest/v1/rpc/get_member_notifications_v2\",{member_filter:selected,member_limit:limit,member_offset:start})}\n  async function loadTop(){var root=q(\"[data-notification-center]\");if(!root)return;var list=q(\"[data-notification-list]\",root),badge=q(\"[data-notification-badge]\",root);if(!session()){list.innerHTML='<div class=\"notification-empty\">'+esc(copy.signInTitle)+'</div>';badge.classList.add(\"hidden\");return}try{var data=await fetchInbox(\"all\",8,0),items=Array.isArray(data&&data.items)?data.items:[],unread=Number(data&&data.unread||0);list.innerHTML=items.length?items.map(function(item){return card(item,false)}).join(\"\"):'<div class=\"notification-empty\">'+esc(copy.emptyAll)+'</div>';badge.textContent=unread>99?\"99+\":String(unread);badge.classList.toggle(\"hidden\",unread===0)}catch(error){list.innerHTML='<div class=\"notification-empty\">'+esc(error.message&&error.message.indexOf(\"profile_required\")>=0?copy.profileRequired:copy.signInTitle)+'</div>';badge.classList.add(\"hidden\")}}\n  function renderHub(data,append){var root=q(\"[data-notification-hub]\");if(!root)return;var list=q(\"[data-notification-hub-list]\",root),items=Array.isArray(data&&data.items)?data.items:[];hubItems=append?hubItems.concat(items):items;list.innerHTML=hubItems.length?hubItems.map(function(item){return card(item,true)}).join(\"\"):'<div class=\"notification-hub-empty\"><strong>'+esc(filter===\"unread\"?copy.emptyUnread:copy.emptyAll)+'</strong></div>';q(\"[data-notification-unread]\",root).textContent=String(Number(data&&data.unread||0));q(\"[data-notification-load-more]\",root).classList.toggle(\"hidden\",hubItems.length>=Number(data&&data.total||0))}\n  async function loadHub(append){var root=q(\"[data-notification-hub]\");if(!root)return;if(!session()){gate(q(\"[data-notification-hub-list]\",root),false);q(\"[data-notification-load-more]\",root).classList.add(\"hidden\");return}if(!append){offset=0;q(\"[data-notification-hub-list]\",root).innerHTML='<div class=\"notification-hub-empty\"><span>'+esc(copy.loading)+'</span></div>'}try{var data=await fetchInbox(filter,pageSize,offset);renderHub(data,append)}catch(error){gate(q(\"[data-notification-hub-list]\",root),error.message&&error.message.indexOf(\"profile_required\")>=0);q(\"[data-notification-load-more]\",root).classList.add(\"hidden\")}}\n  async function markOne(id){try{await api(\"/rest/v1/rpc/mark_member_notification_read\",{target_notification:id})}catch(error){}}\n  async function markAll(){try{await api(\"/rest/v1/rpc/mark_member_notifications_read\",{});hubItems=[];await Promise.all([loadTop(),loadHub(false)])}catch(error){}}\n  function bindTop(){var root=q(\"[data-notification-center]\");if(!root)return;var toggle=q(\"[data-notifications-toggle]\",root),popover=q(\"[data-notification-popover]\",root),mark=q(\"[data-mark-notifications-read]\",root);toggle.addEventListener(\"click\",function(event){event.stopPropagation();popover.classList.toggle(\"hidden\");if(!popover.classList.contains(\"hidden\"))loadTop()});mark.addEventListener(\"click\",function(event){event.stopPropagation();markAll()});document.addEventListener(\"click\",function(event){if(!root.contains(event.target))popover.classList.add(\"hidden\")})}\n  function bindHub(){var root=q(\"[data-notification-hub]\");if(!root)return;q(\"[data-notification-filters]\",root).addEventListener(\"click\",function(event){var button=event.target.closest(\"[data-notification-filter]\");if(!button)return;filter=button.getAttribute(\"data-notification-filter\");qa(\"[data-notification-filter]\",root).forEach(function(item){item.classList.toggle(\"active\",item===button)});hubItems=[];loadHub(false)});q(\"[data-notification-mark-all]\",root).addEventListener(\"click\",markAll);q(\"[data-notification-load-more]\",root).addEventListener(\"click\",function(){offset+=pageSize;loadHub(true)})}\n  document.addEventListener(\"click\",function(event){var link=event.target.closest(\"[data-notification-link]\");if(!link)return;event.preventDefault();var destination=link.href;markOne(link.getAttribute(\"data-notification-id\")).finally(function(){location.href=destination})});\n  document.addEventListener(\"DOMContentLoaded\",function(){bindTop();bindHub();loadTop();loadHub(false);setInterval(function(){if(!document.hidden){loadTop();if(q(\"[data-notification-hub]\"))loadHub(false)}},15000)});\n  document.addEventListener(\"visibilitychange\",function(){if(!document.hidden){loadTop();if(q(\"[data-notification-hub]\"))loadHub(false)}});\n  window.addEventListener(\"focus\",function(){loadTop()});\n})();";

