  var config=window.__FN_CONFIG__||{},page=window.__FN_PAGE__||{},copy=page.verificationAdmin||{},storageKey="football_network_session",kind="identity",offset=0,pageSize=30,total=0,items=[],selected=null,staffRole="";
  var gate=root.querySelector("[data-admin-gate]"),workspace=root.querySelector("[data-admin-workspace]"),filter=root.querySelector("[data-admin-filter]"),queue=root.querySelector("[data-admin-queue]"),detail=root.querySelector("[data-admin-detail]"),feedback=root.querySelector("[data-admin-feedback]"),loadMore=root.querySelector("[data-admin-load-more]");
  function esc(value){return String(value==null?"":value).replace(/[&<>"']/g,function(ch){return{"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[ch]})}
